<template><Teleport to="body"><div v-if="open" class="fixed inset-0 z-[100] flex items-end justify-center bg-black/30 lg:items-center lg:p-6"><section class="flex h-[100dvh] w-full flex-col bg-[#f3f6f8] lg:h-[90vh] lg:max-w-[460px] lg:rounded-3xl"><header class="flex items-center gap-3 bg-white px-4 py-3"><button class="text-3xl" @click="close">‹</button><div class="flex-1"><b>一家卡券充值店</b><p class="text-xs text-orange-500">真实体验分5.0 ★★★★★</p></div><button class="rounded-full border px-3 py-1">店铺</button><button @click="soon">•••</button></header><iframe :src="url" class="min-h-0 flex-1 border-0" title="店铺客服聊天"/><footer class="bg-white p-3 pb-[max(12px,env(safe-area-inset-bottom))]"><div class="mb-2 flex gap-2 text-xs"><button v-for="x in ['评价客服','猜你喜欢','店铺上新']" :key="x" @click="soon">{{x}}</button></div><div class="flex gap-3"><span>🎙</span><span class="flex-1 rounded bg-gray-100 px-2 text-gray-400">输入消息</span><span>😊 🛍</span><button @click="more=!more">{{more?'×':'+'}}</button></div><div v-if="more" class="grid grid-cols-4 gap-3 pt-4 text-center"><button v-for="x in tools" :key="x" class="rounded bg-gray-100 p-3 text-xs" @click="soon">{{x}}</button></div></footer></section></div></Teleport></template>
<script setup lang="ts">import{onMounted,onBeforeUnmount,ref}from'vue';const open=ref(false),more=ref(false),url=ref(''),tools=['拍摄','相册','订单','商品','价保','工单进度','打款','文件'];const show=(e:Event)=>{url.value=(e as CustomEvent<string>).detail;open.value=true},close=()=>{open.value=false;more.value=false},soon=()=>alert('该功能即将上线');onMounted(()=>addEventListener('koshop:open-chat',show));onBeforeUnmount(()=>removeEventListener('koshop:open-chat',show))</script>
